#!/usr/bin/env node
/**
 * generate-knowledge.mjs
 *
 * Reads the ae-ai-starter verified corpus and writes TypeScript data modules
 * into src/js/lib/knowledge/data/.
 *
 * Usage:
 *   node scripts/generate-knowledge.mjs
 *   node scripts/generate-knowledge.mjs --source ../ae-ai-starter/Scripts/verified
 *
 * The generated files are committed to the repo — no runtime dependency on the corpus.
 */

import { readFileSync, writeFileSync, readdirSync, mkdirSync, existsSync } from "fs";
import { join, resolve, dirname, basename, extname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));

// Parse CLI args
const args = process.argv.slice(2);
const sourceArgIdx = args.indexOf("--source");
const sourcePath =
  sourceArgIdx !== -1
    ? resolve(args[sourceArgIdx + 1])
    : resolve(__dirname, "..", "..", "ae-ai-starter", "Scripts", "verified");

if (!existsSync(sourcePath)) {
  console.error(`Error: Source path not found: ${sourcePath}`);
  console.error("Pass --source <path> to specify the verified corpus directory.");
  process.exit(1);
}

const effectsDir = join(sourcePath, "effects");
const gotchasFile = join(sourcePath, "gotchas.md");
const outputDir = resolve(__dirname, "..", "src", "js", "lib", "knowledge", "data");

if (!existsSync(effectsDir)) {
  console.error(`Error: Effects directory not found: ${effectsDir}`);
  process.exit(1);
}

if (!existsSync(gotchasFile)) {
  console.error(`Error: gotchas.md not found: ${gotchasFile}`);
  process.exit(1);
}

mkdirSync(outputDir, { recursive: true });

// ── Generate effect index ────────────────────────────────────────────────────

const effectFiles = readdirSync(effectsDir)
  .filter((f) => f.endsWith(".json") && !f.startsWith("_"))
  .sort();

const indexLines = [];
const doNotUseWarnings = []; // Extra warnings for dangerous aliases
const catalog = {}; // Full property data for Phase 2 message context

for (const file of effectFiles) {
  try {
    const raw = readFileSync(join(effectsDir, file), "utf-8");
    const effect = JSON.parse(raw);

    if (!effect.displayName || !effect.matchName) continue;

    indexLines.push(`${effect.displayName} | ${effect.matchName}`);

    // Collect dangerous aliases for the warning block
    if (effect.knownAliases?.doNotUse?.length) {
      for (const alias of effect.knownAliases.doNotUse) {
        doNotUseWarnings.push(
          `  - "${alias}" is WRONG for ${effect.displayName} — use "${effect.matchName}"`
        );
      }
    }

    // Collect full property data for the detail catalog
    const keywordSet = new Set([
      effect.displayName.toLowerCase(),
      ...(effect.knownAliases?.work || []).map((a) => a.toLowerCase()),
      effect.matchName.toLowerCase(),
    ]);
    const properties = (effect.properties || [])
      .filter((p) => p.valueType !== "NO_VALUE" && p.name !== "")
      .map((p) => ({
        index: p.index,
        name: p.name,
        matchName: p.matchName,
        valueType: p.valueType,
        defaultValue: p.defaultValue ?? null,
      }));
    catalog[effect.matchName] = {
      displayName: effect.displayName,
      matchName: effect.matchName,
      keywords: Array.from(keywordSet),
      doNotUse: effect.knownAliases?.doNotUse || [],
      warnings: effect.warnings || [],
      properties,
    };
  } catch {
    console.warn(`Warning: Could not parse ${file}`);
  }
}

const warningBlock =
  doNotUseWarnings.length > 0
    ? `\n\nKnown Wrong matchNames (DO NOT USE):\n${doNotUseWarnings.join("\n")}`
    : "";

const effectIndexContent = indexLines.join("\n") + warningBlock;

writeFileSync(
  join(outputDir, "effect-index.ts"),
  `// AUTO-GENERATED by scripts/generate-knowledge.mjs — do not edit manually
// Source: ae-ai-starter/Scripts/verified/effects/ (${indexLines.length} effects)

export const EFFECT_INDEX = ${JSON.stringify(effectIndexContent)};
`
);

console.log(`✓ effect-index.ts — ${indexLines.length} effects`);
if (doNotUseWarnings.length > 0) {
  console.log(`  + ${doNotUseWarnings.length} dangerous alias warnings`);
}

// ── Generate gotchas ─────────────────────────────────────────────────────────

const gotchasContent = readFileSync(gotchasFile, "utf-8");

writeFileSync(
  join(outputDir, "gotchas.ts"),
  `// AUTO-GENERATED by scripts/generate-knowledge.mjs — do not edit manually
// Source: ae-ai-starter/Scripts/verified/gotchas.md

export const GOTCHAS = ${JSON.stringify(gotchasContent)};
`
);

console.log(`✓ gotchas.ts — ${gotchasContent.split("\n").length} lines`);

// ── Generate effects detail catalog ──────────────────────────────────────────

const catalogEntries = Object.keys(catalog).length;

writeFileSync(
  join(outputDir, "effects-detail.ts"),
  `// AUTO-GENERATED by scripts/generate-knowledge.mjs — do not edit manually
// Source: ae-ai-starter/Scripts/verified/effects/ (${catalogEntries} effects)

export interface EffectDetail {
  displayName: string;
  matchName: string;
  keywords: string[];
  doNotUse: string[];
  warnings: string[];
  properties: Array<{
    index: number;
    name: string;
    matchName: string;
    valueType: string;
    defaultValue: number | number[] | null;
  }>;
}

export const EFFECTS_DETAIL: Record<string, EffectDetail> = ${JSON.stringify(catalog)};
`
);

console.log(`✓ effects-detail.ts — ${catalogEntries} effects`);
console.log(`\nDone. Files written to src/js/lib/knowledge/data/`);
